public int active()
{
    int                 ret;
    FormDataSource      SalesTable_DS    = any2Object(this) as FormDataSource;
    formRun             formRun          = SalesTable_DS.formRun();
    SalesTable          SalesTable       = SalesTable_ds.cursor();
    FormControl     workflowFormMenu = formRun.design().controlName("ETGSalesEditLines");

    ret = next active();

    //CS, DLT, Abhinav 28012025
    if(ETGACFParameters::find().EnableSalesInvoiceWorkflow == NoYes::Yes)
    {

        CustPackingSlipJour custPackingSlipJourLoc;
        select firstonly RecId from custPackingSlipJourLoc where custPackingSlipJourLoc.SalesId == SalesTable.SalesId;

        if(custPackingSlipJourLoc.RecId)
        {
            workflowFormMenu.enabled(true);
        }
        else
        {
            workflowFormMenu.enabled(false);
        }
    }
    else
    {
        workflowFormMenu.visible(false);
    }
    //CE, DLT, Abhinav 28012025

    return ret;
}
